import { experimental_createTool } from "@composio/core";
import { z } from "zod/v3";
import { runAppleScript } from "./applescript";

const SEND_SCRIPT = `on run {targetBuddy, targetText}
	tell application "Messages"
		set targetService to 1st service whose service type = iMessage
		send targetText to buddy targetBuddy of targetService
	end tell
end run`;

// "Think" time + time to type the message, with jitter, capped so messages
// don't fire instantly.
function humanDelayMs(text: string): number {
  const think = 800 + Math.random() * 1700; // 0.8–2.5s
  const typing = text.length * (40 + Math.random() * 40); // ~40–80ms/char
  return Math.min(think + typing, 12_000);
}

export const sendMessage = experimental_createTool("SEND", {
  name: "Send iMessage",
  description:
    "Send an iMessage from the user's Mac to a phone number or iMessage email handle.",
  preload: true,
  inputParams: z.object({
    to: z
      .string()
      .describe("Recipient handle: phone number (e.g. +15551234567) or iMessage email."),
    text: z.string().describe("Message body to send."),
    name: z.string().optional().describe("Recipient's contact name, for display."),
  }),
  execute: async ({ to, text }) => {
    await new Promise((r) => setTimeout(r, humanDelayMs(text)));
    await runAppleScript(SEND_SCRIPT, [to, text]);
    return { sent: true, to };
  },
});

import { experimental_createTool } from "@composio/core";
import Fuse from "fuse.js";
import { z } from "zod/v3";
import { normalizeHandle } from "../imessage/handles";
import { runAppleScript } from "./applescript";

type Contact = {
  name: string;
  nickname: string;
  initials: string;
  numbers: { label: string; value: string }[];
};

// Emits one line per person: name|nickname|label=value;label=value
//
// Bulk-fetches each property for ALL people in one Apple Event apiece (a few
// IPC round-trips total), then assembles locally. Reading properties per-person
// inside a loop is thousands of round-trips and is what made this slow.
const CONTACTS_SCRIPT = `tell application "Contacts"
	set theNames to name of every person
	set theNicks to nickname of every person
	set theVals to value of phones of every person
	set theLbls to label of phones of every person
end tell
set out to {}
repeat with i from 1 to count of theNames
	set nm to item i of theNames
	if nm is missing value then set nm to ""
	set nk to item i of theNicks
	if nk is missing value then set nk to ""
	set vals to item i of theVals
	set lbls to item i of theLbls
	set phParts to {}
	repeat with j from 1 to count of vals
		set lb to item j of lbls
		if lb is missing value then set lb to "other"
		set end of phParts to (lb & "=" & item j of vals)
	end repeat
	set AppleScript's text item delimiters to ";"
	set phStr to phParts as text
	set AppleScript's text item delimiters to ""
	set end of out to (nm & "|" & nk & "|" & phStr)
end repeat
set AppleScript's text item delimiters to (ASCII character 10)
return out as text`;

function cleanLabel(raw: string): string {
  return raw.replace(/^_\$!<(.+)>!\$_$/, "$1") || "other";
}

function initialsOf(name: string): string {
  return name
    .split(/\s+/)
    .filter(Boolean)
    .map((w) => w[0])
    .join("")
    .toLowerCase();
}

function parseContact(line: string): Contact | null {
  const [name = "", nickname = "", phonesPart = ""] = line.split("|");
  const numbers = phonesPart
    .split(";")
    .filter(Boolean)
    .map((entry) => {
      const idx = entry.indexOf("=");
      return { label: cleanLabel(entry.slice(0, idx)), value: entry.slice(idx + 1).trim() };
    })
    .filter((n) => n.value);
  if (!name || numbers.length === 0) return null;
  return { name, nickname, initials: initialsOf(name), numbers };
}

let contactsCache: Contact[] | null = null;

async function loadContacts(): Promise<Contact[]> {
  if (contactsCache) return contactsCache;
  const stdout = await runAppleScript(CONTACTS_SCRIPT);
  contactsCache = stdout
    .split("\n")
    .map((l) => parseContact(l.trim()))
    .filter((c): c is Contact => c !== null);
  return contactsCache;
}

export async function searchContacts(
  query: string,
  limit = 5,
): Promise<{ name: string; numbers: { label: string; value: string }[] }[]> {
  const contacts = await loadContacts();
  const fuse = new Fuse(contacts, {
    keys: ["name", "nickname", "initials"],
    threshold: 0.4,
    ignoreLocation: true,
  });
  return fuse
    .search(query)
    .slice(0, limit)
    .map((r) => ({ name: r.item.name, numbers: r.item.numbers }));
}

// Reverse lookup: contact name for an incoming handle (for nicer prompts).
export async function nameForHandle(handle: string): Promise<string | null> {
  const target = normalizeHandle(handle);
  for (const c of await loadContacts()) {
    for (const n of c.numbers) {
      if (normalizeHandle(n.value) === target) return c.name;
    }
  }
  return null;
}

export const findContact = experimental_createTool("FIND_CONTACT", {
  name: "Find Contact",
  description:
    "Fuzzy-search the user's Mac contacts by name, nickname, or initials. Returns matching contacts with their phone numbers (labeled). Use this to resolve who a message is for before sending.",
  preload: true,
  inputParams: z.object({
    query: z.string().describe("Name, nickname, or initials to search for (e.g. 'sh')."),
  }),
  execute: async ({ query }) => ({ candidates: await searchContacts(query) }),
});

import { experimental_createTool } from "@composio/core";
import { z } from "zod/v3";
import { decodeAttributedBody, runSqlite } from "../imessage/chat-db";

// Apple stores message dates as ns since 2001-01-01; 978307200 = that in unix epoch.
function buildQuery(limit: number, handle?: string): string {
  const select = `SELECT
  CASE WHEN m.is_from_me = 1 THEN 'me' ELSE h.id END AS sender,
  datetime(m.date / 1000000000 + 978307200, 'unixepoch', 'localtime') AS time,
  m.text AS text,
  CASE WHEN m.text IS NULL THEN hex(m.attributedBody) ELSE NULL END AS bodyHex
FROM message m
LEFT JOIN handle h ON m.handle_id = h.ROWID`;

  if (handle) {
    const safe = handle.replace(/'/g, "''");
    return `${select}
JOIN chat_message_join cmj ON cmj.message_id = m.ROWID
WHERE cmj.chat_id IN (
  SELECT chj.chat_id FROM chat_handle_join chj
  JOIN handle hh ON hh.ROWID = chj.handle_id
  WHERE hh.id = '${safe}'
)
ORDER BY m.date DESC LIMIT ${limit};`;
  }
  return `${select}
ORDER BY m.date DESC LIMIT ${limit};`;
}

type Row = { sender: string | null; time: string; text: string | null; bodyHex: string | null };

export const readMessages = experimental_createTool("READ_MESSAGES", {
  name: "Read iMessages",
  description:
    "Read recent iMessages from the user's Mac. Defaults to the last 5. Pass a larger limit to see more, or a handle (a phone/email, e.g. from find_contact) to read one conversation.",
  preload: true,
  inputParams: z.object({
    handle: z
      .string()
      .optional()
      .describe("Phone number or email to focus on a single conversation."),
    limit: z
      .number()
      .int()
      .optional()
      .describe("How many recent messages to read (default 5, max 50)."),
  }),
  execute: async ({ handle, limit }) => {
    const n = Math.min(Math.max(limit ?? 5, 1), 50);
    const rows = await runSqlite<Row>(buildQuery(n, handle));
    const messages = rows
      .reverse() // chronological: oldest first
      .map((r) => ({
        sender: r.sender ?? "unknown",
        time: r.time,
        text: r.text ?? decodeAttributedBody(r.bodyHex) ?? "[unsupported message]",
      }));
    return { messages };
  },
});

import { experimental_createTool } from "@composio/core";
import { z } from "zod/v3";
import { readMemory, writeMemory } from "../imessage/memory";

export const recallContact = experimental_createTool("RECALL", {
  name: "Recall Contact",
  description:
    "Recall what you remember about a contact (notes from past conversations) by their phone/email handle. Call this before replying to or discussing someone.",
  preload: true,
  inputParams: z.object({
    handle: z.string().describe("Phone number or email of the contact."),
  }),
  execute: async ({ handle }) => ({ notes: await readMemory(handle) }),
});

export const rememberContact = experimental_createTool("REMEMBER", {
  name: "Remember Contact",
  description:
    "Save concise notes about a contact (facts, ongoing topics, plans) for future conversations. Replaces the existing notes, so pass the full updated notes. Keep them short, a few lines.",
  preload: true,
  inputParams: z.object({
    handle: z.string().describe("Phone number or email of the contact."),
    notes: z.string().describe("The full updated notes to store (concise)."),
  }),
  execute: async ({ handle, notes }) => {
    await writeMemory(handle, notes);
    return { saved: true };
  },
});

import { execFile } from "node:child_process";
import { promisify } from "node:util";

const run = promisify(execFile);

// Runs an AppleScript via osascript. `--` ends osascript option parsing; extra
// values then become `on run {…}` parameters and are never parsed as source.
export async function runAppleScript(script: string, args: string[] = []): Promise<string> {
  const { stdout } = await run("osascript", ["-e", script, "--", ...args], {
    maxBuffer: 1024 * 1024 * 16,
    timeout: 60_000,
  });
  return stdout;
}

import { experimental_createToolkit } from "@composio/core";
import { findContact } from "./find-contact";
import { recallContact, rememberContact } from "./memory-tools";
import { readMessages } from "./read-messages";
import { sendMessage } from "./send-message";

// A self-contained Composio custom toolkit for local iMessage on macOS:
// send, find contacts, read messages, and per-contact memory. Framework-agnostic
export function createImessageToolkit() {
  return experimental_createToolkit("IMESSAGE", {
    name: "iMessage",
    description:
      "Send and read iMessages, look up contacts, and remember things about them, locally on the user's Mac.",
    tools: [sendMessage, findContact, readMessages, recallContact, rememberContact],
  });
}

